// src/components/SignInForm.tsx
"use client";
import Image from "next/image";
import { FormEvent, useEffect, useState } from "react";
import { signIn, useSession } from "next-auth/react";
import { useRouter, useSearchParams } from "next/navigation";

export default function SignInForm() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const { status } = useSession();

    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(false);

    const callbackUrl = searchParams.get("callbackUrl") || "/";

    useEffect(() => {
        if (status === "authenticated") {
            router.replace(callbackUrl);
        }
    }, [status, router, callbackUrl]);

    const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
        event.preventDefault();
        setError(null);
        setIsLoading(true);

        const result = await signIn("credentials", {
            email,
            password,
            redirect: false,
            callbackUrl,
        });

        if (result?.error) {
            setError("Invalid credentials");
            setIsLoading(false);
            return;
        }

        router.replace(result?.url || callbackUrl);
        router.refresh();
    };

    return (
        <main className="relative w-full h-screen flex items-center justify-center overflow-hidden font-serif">
            <div className="absolute inset-0 z-0">
                <Image 
                    src="/img/signin-bg.jpg" 
                    alt="Background" 
                    fill 
                    priority 
                    className="object-cover scale-105 blur-[2px]" 
                />
                <div className="absolute inset-0 bg-black/60 bg-linear-to-b from-black/20 via-black/60 to-black/80"></div>
            </div>

            <div className="relative z-10 w-full max-w-md p-12 mx-4 backdrop-blur-3xl bg-white/3 border border-white/10 rounded-[3rem] shadow-2xl text-white">
                <div className="text-center mb-10">
                    <h1 className="text-4xl mb-4 tracking-tight font-serif italic">Sign In</h1>
                    <p className="text-stone-400 font-sans text-[10px] uppercase tracking-[0.3em] opacity-80">Access your garage</p>
                </div>

                <form className="space-y-5 font-sans" onSubmit={handleSubmit}>
                    <div className="space-y-2">
                        <label className="block text-[10px] uppercase tracking-[0.3em] text-stone-500 ml-5 font-bold">Email</label>
                        <input
                            type="email"
                            placeholder="email@example.com"
                            className="w-full bg-white/5 border border-white/10 rounded-full px-8 py-4 outline-none focus:border-amber-500/40 focus:bg-white/10 transition-all text-sm placeholder:text-stone-700"
                            value={email}
                            onChange={(event) => setEmail(event.target.value)}
                            required
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="block text-[10px] uppercase tracking-[0.3em] text-stone-500 ml-5 font-bold">Password</label>
                        <input
                            type="password"
                            placeholder="••••••••"
                            className="w-full bg-white/5 border border-white/10 rounded-full px-8 py-4 outline-none focus:border-amber-500/40 focus:bg-white/10 transition-all text-sm placeholder:text-stone-700"
                            value={password}
                            onChange={(event) => setPassword(event.target.value)}
                            required
                        />
                    </div>

                    {error && <p className="text-red-300 text-sm px-4">{error}</p>}

                    <div className="pt-4">
                        <button
                            type="submit"
                            disabled={isLoading}
                            className="w-full bg-white text-black py-5 rounded-full font-bold uppercase text-[11px] tracking-[0.3em] hover:bg-amber-600 hover:text-white transition-all duration-500 disabled:opacity-60 disabled:cursor-not-allowed"
                        >
                            {isLoading ? "Signing In..." : "Sign In"}
                        </button>
                    </div>
                </form>
            </div>
        </main>
    );
}